BEGIN TRANSACTION;CREATE TABLE category (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE
);INSERT INTO "category" VALUES(1,'Женская обувь');INSERT INTO "category" VALUES(2,'Мужская обувь');CREATE TABLE customer_order (
    id INTEGER PRIMARY KEY,
    order_date TEXT NOT NULL,
    delivery_date TEXT NOT NULL,
    pickup_point_id INTEGER NOT NULL REFERENCES pickup_point(id),
    customer_id INTEGER NOT NULL REFERENCES user(id),
    receive_code INTEGER NOT NULL,
    status_id INTEGER NOT NULL REFERENCES order_status(id)
);INSERT INTO "customer_order" VALUES(1,'2025-02-27','2025-04-20',1,4,901,2);INSERT INTO "customer_order" VALUES(2,'2022-09-28','2025-04-21',11,1,902,2);INSERT INTO "customer_order" VALUES(3,'2025-03-21','2025-04-22',2,2,903,2);INSERT INTO "customer_order" VALUES(4,'2025-02-20','2025-04-23',11,3,904,2);INSERT INTO "customer_order" VALUES(5,'2025-03-17','2025-04-24',2,4,905,2);INSERT INTO "customer_order" VALUES(6,'2025-03-01','2025-04-25',15,1,906,2);INSERT INTO "customer_order" VALUES(7,'30.02.2025','2025-04-26',3,2,907,2);INSERT INTO "customer_order" VALUES(8,'2025-03-31','2025-04-27',19,3,908,1);INSERT INTO "customer_order" VALUES(9,'2025-04-02','2025-04-28',5,4,909,1);INSERT INTO "customer_order" VALUES(10,'2025-04-03','2025-04-29',19,4,910,1);CREATE TABLE manufacturer (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE
);INSERT INTO "manufacturer" VALUES(1,'Alessio Nesca');INSERT INTO "manufacturer" VALUES(2,'CROSBY');INSERT INTO "manufacturer" VALUES(3,'Kari');INSERT INTO "manufacturer" VALUES(4,'Marco Tozzi');INSERT INTO "manufacturer" VALUES(5,'Rieker');INSERT INTO "manufacturer" VALUES(6,'Рос');CREATE TABLE order_item (
