    id INTEGER PRIMARY KEY AUTOINCREMENT,
    article TEXT NOT NULL UNIQUE,
    name TEXT NOT NULL,
    unit_id INTEGER NOT NULL REFERENCES unit(id),
    price REAL NOT NULL CHECK(price >= 0),
    supplier_id INTEGER NOT NULL REFERENCES supplier(id),
    manufacturer_id INTEGER NOT NULL REFERENCES manufacturer(id),
    category_id INTEGER NOT NULL REFERENCES category(id),
    discount_percent INTEGER NOT NULL DEFAULT 0 CHECK(discount_percent >= 0 AND discount_percent <= 100),
    stock_quantity INTEGER NOT NULL DEFAULT 0 CHECK(stock_quantity >= 0),
    description TEXT NOT NULL,
    image_path TEXT
);INSERT INTO "product" VALUES(1,'А112Т4','Ботинки',1,4990.0,1,3,1,3,6,'Женские Ботинки демисезонные kari','resources/images/1.jpg');INSERT INTO "product" VALUES(2,'F635R4','Ботинки',1,3244.0,2,4,1,2,13,'Ботинки Marco Tozzi женские демисезонные, размер 39, цвет бежевый','resources/images/2.jpg');INSERT INTO "product" VALUES(3,'H782T5','Туфли',1,4499.0,1,3,2,4,5,'Туфли kari мужские классика MYZ21AW-450A, размер 43, цвет: черный','resources/images/3.jpg');INSERT INTO "product" VALUES(4,'G783F5','Ботинки',1,5900.0,1,6,2,2,8,'Мужские ботинки Рос-Обувь кожаные с натуральным мехом','resources/images/4.jpg');INSERT INTO "product" VALUES(5,'J384T6','Ботинки',1,3800.0,2,5,2,2,16,'B3430/14 Полуботинки мужские Rieker','resources/images/5.jpg');INSERT INTO "product" VALUES(6,'D572U8','Кроссовки',1,4100.0,2,6,2,3,6,'129615-4 Кроссовки мужские','resources/images/6.jpg');INSERT INTO "product" VALUES(7,'F572H7','Туфли',1,2700.0,1,4,1,2,14,'Туфли Marco Tozzi женские летние, размер 39, цвет черный','resources/images/7.jpg');INSERT INTO "product" VALUES(8,'D329H3','Полуботинки',1,1890.0,2,1,1,4,4,'Полуботинки Alessio Nesca женские 3-30797-47, размер 37, цвет: бордовый','resources/images/8.jpg');INSERT INTO "product" VALUES(9,'B320R5','Туфли',1,4300.0,1,5,1,2,6,'Туфли Rieker женские демисезонные, размер 41, цвет коричневый','resources/images/9.jpg');INSERT INTO "product" VALUES(10,'G432E4','Туфли',1,2800.0,1,3,1,3,15,'Туфли kari женские TR-YR-413017, размер 37, цвет: черный','resources/images/10.jpg');INSERT INTO "product" VALUES(11,'S213E3','Полуботинки',1,2156.0,2,2,2,3,6,'407700/01-01 Полуботинки мужские CROSBY','resources/images/picture.png');INSERT INTO "product" VALUES(12,'E482R4','Полуботинки',1,1800.0,1,3,1,2,14,'Полуботинки kari женские MYZ20S-149, размер 41, цвет: черный','resources/images/picture.png');INSERT INTO "product" VALUES(13,'S634B5','Кеды',1,5500.0,2,2,2,3,0,'Кеды Caprice мужские демисезонные, размер 42, цвет черный','resources/images/picture.png');INSERT INTO "pro